# main.tf
resource "aws_ecr_repository" "agent" {
  name                 = "my-agent"
  image_tag_mutability = "MUTABLE"
}

resource "aws_lambda_function" "agent" {
  function_name = "my-agent"
  package_type  = "Image"
  image_uri     = "${aws_ecr_repository.agent.repository_url}:latest"
  role          = aws_iam_role.lambda_exec.arn

  timeout      = 300  # 5 minutes per invocation
  memory_size  = 1024

  environment {
    variables = {
      # Injected at runtime; never baked into the image
      SECRET_ARN = aws_secretsmanager_secret.agent_keys.arn
    }
  }
}

resource "aws_lambda_function_url" "agent" {
  function_name      = aws_lambda_function.agent.function_name
  authorization_type = "AWS_IAM"
}

# Provisioned Concurrency to eliminate cold starts for latency-sensitive paths
resource "aws_lambda_provisioned_concurrency_config" "agent" {
  function_name                  = aws_lambda_function.agent.function_name
  qualifier                      = aws_lambda_alias.live.name
  provisioned_concurrent_executions = 2
}

# agent/config.py — fetch secrets once per cold start
import boto3, json, functools

@functools.lru_cache(maxsize=None)
def get_secret(secret_arn: str) -> dict:
    client = boto3.client("secretsmanager")
    resp = client.get_secret_value(SecretId=secret_arn)
    return json.loads(resp["SecretString"])


def openai_key() -> str:
    import os
    arn = os.environ["SECRET_ARN"]
    return get_secret(arn)["OPENAI_API_KEY"]
